mapper.select:
with recursive dep_tree as ( select id, parent_id, name, code, depth, id as root_id from sys_department where depth = 0
and created_at >= #{dto.startTime}
and created_at <= #{dto.endTime}
union all
select d.id, d.parent_id, d.name, d.code, d.depth, t.root_id from sys_department d join dep_tree t on d.parent_id = t.id
and d.created_at >= #{dto.startTime}
and d.created_at <= #{dto.endTime}
) select distinct r.*, exists (select 1 from sys_department c where c.parent_id = r.id) as hasChildren from dep_tree t join sys_department r on r.id = t.root_id
and (t.name like concat('%', #{dto.keyword}, '%') or t.code like concat('%', #{dto.keyword}, '%')
or t.id = CAST(#{dto.keyword} AS BIGINT)
)

with recursive dep_tree as ( select id, parent_id, name, code, depth, created_at, updated_at, id as root_id from sys_department where parent_id = #{dto.parentId}
and created_at >= #{dto.startTime}
and created_at <= #{dto.endTime}
union all select d.id, d.parent_id, d.name, d.code, d.depth, d.created_at, d.updated_at, t.root_id from sys_department d join dep_tree t on d.parent_id = t.id
and d.created_at >= #{dto.startTime}
and d.created_at <= #{dto.endTime}
) select distinct r.*, exists (select 1 from sys_department c where c.parent_id = r.id) as hasChildren from dep_tree t join sys_department r on r.id = t.root_id
and (t.name like concat('%', #{dto.keyword}, '%') or t.code like concat('%', #{dto.keyword}, '%')
or t.id = CAST(#{dto.keyword} AS BIGINT)
)

mapper.update:
WITH RECURSIVE dep_tree AS (SELECT id FROM sys_department WHERE parent_id = #{id}
UNION ALL
SELECT d.id FROM sys_department d JOIN dep_tree dt ON d.parent_id = dt.id) UPDATE sys_department SET is_active = FALSE, updated_at = NOW() WHERE id IN (SELECT id FROM dep_tree)

